import * as React from "react";
import { AlarmClock } from "lucide-react";

import { cn } from "@/lib/utils";

import "./jitter-animation.css";

export type JitterAxis = "both" | "horizontal" | "vertical";
export type JitterAnimationAxis = JitterAxis;

export type JitterProps = React.ComponentPropsWithoutRef<"span"> & {
  /** The axis the content jitters on. Defaults to horizontal. */
  axis?: JitterAxis;
  /** Classes applied to the animated child wrapper. */
  targetClassName?: string;
};

export function Jitter({
  axis = "horizontal",
  className,
  children,
  targetClassName,
  ...props
}: JitterProps) {
  return (
    <span
      data-slot="jitter"
      data-axis={axis}
      className={cn("jitter inline-flex", className)}
      {...props}
    >
      <span
        data-slot="jitter-target"
        className={cn("jitter-target inline-flex", targetClassName)}
      >
        {children}
      </span>
    </span>
  );
}

export type JitterAnimationProps = React.ComponentPropsWithoutRef<"div"> & {
  /** The axis the icon jitters on. Defaults to horizontal. */
  axis?: JitterAxis;
};

export function JitterAnimation({
  axis = "horizontal",
  className,
  ...props
}: JitterAnimationProps) {
  return (
    <div
      data-slot="jitter-animation"
      data-axis={axis}
      className={cn(
        "jitter jitter-animation flex flex-col items-center text-foreground",
        className,
      )}
      {...props}
    >
      <div
        data-slot="jitter-animation-target"
        className="jitter-target w-full max-w-72"
      >
        <AlarmClock aria-hidden="true" className="h-auto w-full" />
      </div>
    </div>
  );
}

.jitter-animation {
  --jitter-animation-x: 3px;
  --jitter-animation-y: 0px;
}

.jitter-target {
  backface-visibility: hidden;
  transform-origin: center;
  animation: jitter-animation 480ms steps(1, end) both;
  will-change: transform;
}

.jitter-animation[data-axis="vertical"] {
  --jitter-animation-x: 0px;
  --jitter-animation-y: 3px;
}

.jitter-animation[data-axis="both"] {
  --jitter-animation-x: 3px;
  --jitter-animation-y: 2px;
}

.jitter[data-axis="both"] .jitter-target {
  animation-name: jitter-animation-both;
}

@keyframes jitter-animation {
  0%,
  100% {
    transform: translate3d(0, 0, 0);
  }
  8% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * -1),
      calc(var(--jitter-animation-y) * 1),
      0
    );
  }
  16% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * 0.9),
      calc(var(--jitter-animation-y) * -0.9),
      0
    );
  }
  26% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * -0.8),
      calc(var(--jitter-animation-y) * 0.8),
      0
    );
  }
  36% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * 0.67),
      calc(var(--jitter-animation-y) * -0.67),
      0
    );
  }
  48% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * -0.52),
      calc(var(--jitter-animation-y) * 0.52),
      0
    );
  }
  60% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * 0.4),
      calc(var(--jitter-animation-y) * -0.4),
      0
    );
  }
  72% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * -0.27),
      calc(var(--jitter-animation-y) * 0.27),
      0
    );
  }
  84% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * 0.15),
      calc(var(--jitter-animation-y) * -0.15),
      0
    );
  }
  92% {
    transform: translate3d(
      calc(var(--jitter-animation-x) * -0.07),
      calc(var(--jitter-animation-y) * 0.07),
      0
    );
  }
}

@keyframes jitter-animation-both {
  0%,
  100% {
    transform: translate3d(0, 0, 0);
  }
  8% {
    transform: translate3d(-3px, 1.8px, 0);
  }
  16% {
    transform: translate3d(2.7px, -1.8px, 0);
  }
  26% {
    transform: translate3d(-2.4px, -1.6px, 0);
  }
  36% {
    transform: translate3d(2px, 1.34px, 0);
  }
  48% {
    transform: translate3d(-1.56px, 1.04px, 0);
  }
  60% {
    transform: translate3d(1.2px, -0.8px, 0);
  }
  72% {
    transform: translate3d(-0.81px, -0.54px, 0);
  }
  84% {
    transform: translate3d(0.45px, 0.3px, 0);
  }
  92% {
    transform: translate3d(-0.21px, 0.14px, 0);
  }
}

@media (prefers-reduced-motion: reduce) {
  .jitter-target {
    animation: none;
    will-change: auto;
  }
}
